const { exec } = require('child_process');
const path = require('path');

function resizeImage(inputFile, outputFile, dimensions, effects) {
    const allowedEffects = ['grayscale', 'sepia', 'blur', 'enhance'];
    const sanitizedInput = path.basename(inputFile);
    const sanitizedOutput = path.basename(outputFile);
    
    if (!allowedEffects.every(effect => effects.includes(effect))) {
        throw new Error('Invalid effects provided');
    }

    let command = `magick convert ${sanitizedInput} -resize ${dimensions}`;

    effects.forEach(effect => {
        switch (effect) {
            case 'grayscale':
                command += ' -colorspace Gray';
                break;
            case 'sepia':
                command += ' -sepia-tone 80%';
                break;
            case 'blur':
                command += ' -blur 0x8';
                break;
            case 'enhance':
                command += ' -enhance';
                break;
        }
    });

    command += ` ${sanitizedOutput}`;

    exec(command, (error, stdout, stderr) => {
        if (error) {
            console.error(`Error: ${error.message}`);
            return;
        }
        if (stderr) {
            console.error(`stderr: ${stderr}`);
            return;
        }
        console.log(`Image resized and saved as ${sanitizedOutput}`);
    });
}